use fastly::Error;
use fastly::http::{Method, StatusCode, Uri};
use fastly::{Backend, Request, Response};
use std::collections::HashMap;

#[derive(Debug)]
struct BackendConfig {
    host: String,
    port: u16,
    sni: String,
    tls_enabled: bool,
    timeout: u32,
}

impl BackendConfig {
    fn new(host: &str, port: u16, sni: &str, tls_enabled: bool, timeout: u32) -> Self {
        Self {
            host: host.to_string(),
            port,
            sni: sni.to_string(),
            tls_enabled,
            timeout,
        }
    }
}

struct BackendRouter {
    backends: HashMap<String, BackendConfig>,
}

impl BackendRouter {
    fn new() -> Self {
        Self {
            backends: HashMap::new(),
        }
    }

    fn add_backend(&mut self, name: &str, config: BackendConfig) {
        self.backends.insert(name.to_string(), config);
    }

    fn get_backend(&self, name: &str) -> Option<&BackendConfig> {
        self.backends.get(name)
    }
}

fn create_backend_from_config(config: &BackendConfig) -> Result<Backend, Error> {
    let mut backend = Backend::new(&config.host, config.port);
    
    if config.tls_enabled {
        backend = backend
            .with_sni(&config.sni)
            .with_tls_timeout(config.timeout);
    } else {
        backend = backend.with_tls_disabled();
    }
    
    backend = backend.with_connect_timeout(config.timeout);
    
    Ok(backend)
}

fn route_request(req: Request<()>) -> Result<Response<()>, Error> {
    let path = req.get_uri().path();
    
    let router = BackendRouter::new();
    
    // Configure backends
    let mut router = router;
    router.add_backend(
        "api_backend",
        BackendConfig::new("api.example.com", 443, "api.example.com", true, 5000),
    );
    router.add_backend(
        "static_backend",
        BackendConfig::new("static.example.com", 443, "static.example.com", true, 5000),
    );
    router.add_backend(
        "legacy_backend",
        BackendConfig::new("legacy.example.com", 80, "legacy.example.com", false, 3000),
    );
    
    let backend_name = match path {
        "/api/*" => "api_backend",
        "/static/*" => "static_backend",
        _ => "legacy_backend",
    };
    
    if let Some(config) = router.get_backend(backend_name) {
        let backend = create_backend_from_config(config)?;
        
        let mut backend_req = Request::builder()
            .method(req.get_method().clone())
            .uri(req.get_uri().clone())
            .body(())
            .expect("Failed to build backend request");
        
        // Copy headers
        for (name, value) in req.get_headers().iter() {
            if name != "host" {
                backend_req.get_headers_mut().insert(name, value.clone());
            }
        }
        
        // Set backend
        backend_req.set_backend(backend);
        
        // Forward to backend
        let resp = backend_req.send()?;
        Ok(resp)
    } else {
        Ok(Response::builder()
            .status(StatusCode::NOT_FOUND)
            .body("Backend not found")
            .expect("Failed to build response"))
    }
}

#[fastly::main]
fn main(req: Request<()>) -> Result<Response<()>, Error> {
    // Validate request
    if req.get_method() != Method::GET && req.get_method() != Method::POST {
        return Ok(Response::builder()
            .status(StatusCode::METHOD_NOT_ALLOWED)
            .body("Method not allowed")
            .expect("Failed to build response"));
    }
    
    // Sanitize path
    let uri = req.get_uri();
    let path = uri.path();
    
    if path.contains("..") || path.contains("//") {
        return Ok(Response::builder()
            .status(StatusCode::BAD_REQUEST)
            .body("Invalid path")
            .expect("Failed to build response"));
    }
    
    route_request(req)
}